+        SignalStatus::Evaluating,
+        SignalStatus::Disposed,
+    ] {
+        let json = serde_json::to_string(&st).unwrap();
+        let back: SignalStatus = serde_json::from_str(&json).unwrap();
+        assert_eq!(back, st);
+    }
+}
